# Abstract base class for all inventory items
@abstract
class Item:
    id: int
    title: str

    def __init__(self, id: int, title: str):
        self.id = id
        self.title = title

    @abstract
    def get_description(self) -> str:
        ...

    @virtual
    def check_out(self) -> str:
        return f"Checking out: {self.title}"

    @abstract
    def calculate_late_fee(self, days: int) -> float:
        ...

    @abstract
    def get_formatted_id(self) -> str:
        ...

# Book class extending Item
class Book(Item):
    author: str
    page_count: int

    def __init__(self, id: int, title: str, author: str, pages: int):
        super().__init__(id, title)
        self.author = author
        self.page_count = pages

    @override
    def get_formatted_id(self) -> str:
        return f"BK-{self.id}"

    @override
    def get_description(self) -> str:
        return f"Book: {self.title} by {self.author}"

    @override
    def calculate_late_fee(self, days: int) -> float:
        return float(days) * 0.5

# Electronics class extending Item
class Electronics(Item):
    brand: str

    def __init__(self, id: int, title: str, brand: str):
        super().__init__(id, title)
        self.brand = brand

    @override
    def get_formatted_id(self) -> str:
        return f"EL-{self.id}"

    @override
    def get_description(self) -> str:
        return f"Electronics: {self.brand} {self.title}"

    @override
    def calculate_late_fee(self, days: int) -> float:
        return float(days) * 2.0

