# Catalog module - imports from inventory and domains
from inventory import Item, Book, Electronics
from domains import Category, Dimensions, ISearchable, category_name, get_color_for_category

class CatalogEntry(ISearchable):
    item: Item
    category: Category
    dimensions: Dimensions

    def __init__(self, item: Item, cat: Category, dims: Dimensions):
        self.item = item
        self.category = cat
        self.dimensions = dims

    def matches(self, query: str) -> bool:
        return query in self.item.title

    def get_full_info(self) -> str:
        cat_str: str = category_name(self.category)
        color: str = get_color_for_category(self.category)
        return f"{self.item.get_description()} [{cat_str}, {color}]"

    def get_volume(self) -> float:
        return self.dimensions.get_volume()

class Library:
    entries: list[CatalogEntry]

    def __init__(self):
        self.entries = []

    def add_entry(self, entry: CatalogEntry) -> None:
        self.entries.append(entry)

    def find_by_title(self, query: str) -> list[CatalogEntry]:
        result: list[CatalogEntry] = []
        for entry in self.entries:
            if entry.matches(query):
                result.append(entry)
        return result

    def calculate_total_fees(self, days: int, cat: Category) -> float:
        total: float = 0.0
        for entry in self.entries:
            if entry.category == cat:
                fee: float = entry.item.calculate_late_fee(days)
                total = total + fee
        return total
